/**
 * @param {number[]} nums
 * @param {number[][]} edges
 * @return {number}
 */
function solve(nums, edges) {
    const N = nums.length;

    // 1. Build Adjacency List
    const adj = Array(N).fill(0).map(() => []);
    for (const [u, v] of edges) {
        adj[u].push(v);
        adj[v].push(u);
    }

    let count = 0;
    const totalMasks = 1 << N;

    // 2. Iterate through all non-empty subsets (masks from 1 to 2^N - 1)
    for (let M = 1; M < totalMasks; M++) {
        let sum = 0;
        const nodesInS = [];

        // Determine nodes in S and calculate sum (Parity Check)
        for (let i = 0; i < N; i++) {
            if ((M >> i) & 1) {
                sum += nums[i];
                nodesInS.push(i);
            }
        }

        // Check condition 2: Sum of node values is even
        if (sum % 2 !== 0) {
            continue;
        }

        // If there is only one node, it is always connected.
        if (nodesInS.length === 1) {
            count++;
            continue;
        }

        // Check condition 1: Induced subgraph is connected using BFS
        const startNode = nodesInS[0];

        const queue = [startNode];
        const visitedInS = new Set([startNode]);
        let visitedCount = 1;

        let head = 0;
        while(head < queue.length) {
            const u = queue[head++];

            for (const v of adj[u]) {
                // Check 1: Is v in the subset S (i.e., is the v-th bit set in M)?
                const v_in_S = (M >> v) & 1;

                // Check 2: Has v been visited in this traversal?
                if (v_in_S && !visitedInS.has(v)) {
                    visitedInS.add(v);
                    queue.push(v);
                    visitedCount++;
                }
            }
        }

        // Check connectivity
        if (visitedCount === nodesInS.length) {
            count++;
        }
    }

    return count;
}

