    // Adjacency list stores Int indices
    val adj = Array(N) { mutableListOf<Int>() }
    for (edge in edges) {
        // Edges are given as [u_i, v_i] where u_i, v_i are Longs representing indices
        val u = edge[0].toInt()
        val v = edge[1].toInt()
        adj[u].add(v)
        adj[v].add(u)
    }

    var count: Long = 0
    val totalMasks = 1 shl N

    // 2. Iterate through all non-empty subsets (masks from 1 to 2^N - 1)
    for (M in 1 until totalMasks) {
        var sum: Long = 0
        val nodesInS = mutableListOf<Int>()

