                nodesInS.add(i)
            }
        }

        // Check condition 2: Sum of node values is even
        if (sum % 2 != 0L) {
            continue
        }

        val requiredSize = nodesInS.size

        // Single node subsets are always connected
        if (requiredSize == 1) {
            count++
            continue
        }

        // Check condition 1: Induced subgraph is connected using BFS
        val startNode = nodesInS[0]

        // BFS setup
        val queue = java.util.LinkedList<Int>()
        queue.add(startNode)

        // visitedInS tracks nodes reached in S
        val visitedInS = BooleanArray(N) { false }
        visitedInS[startNode] = true
        var visitedCount = 1

        while (queue.isNotEmpty()) {
